/* Tool logo marks for the isometric ecosystem plane. Brand marks are from
   Simple Icons (https://simpleicons.org, CC0), 24x24 viewBox; Slack is split
   into its four arms and Zapier uses its asterisk logomark. Fills are the
   brand colors, but the plane renders everything monochrome via CSS
   (currentColor) - drop that rule to get colored marks back. Generated data:
   edit placement here, visuals in EcosystemLattice.tsx / h2.css. */

export type EcosystemMarkGlyph = { d: string; fill: string };

export type EcosystemLogoMark = {
  id: string;
  label: string;
  /* cell coordinates on the tilted plane's grid */
  col: number;
  row: number;
  /* square glyph edge in px; defaults to the stylesheet size, bump for
     wide flat wordmarks */
  glyphSize?: number;
  glyphs: EcosystemMarkGlyph[];
};

